     1→/**
     2→ * @module ConversationContext
     3→ *
     4→ * Mutable accumulator of all state that changes over the lifetime of a
     5→ * single live conversation.
     6→ *
     7→ * ## Purpose
     8→ * `ConversationContext` is the only place inside the orchestrator that
     9→ * intentionally holds mutable state. It tracks the current and previous
    10→ * turn, conversation history, active instructions, and references to the
    11→ * frozen campaign and knowledge snapshots.
    12→ *
    13→ * ## Ownership
    14→ * Created by the `ConversationOrchestrator` at conversation start and
    15→ * discarded on shutdown. Not persisted — persistence is handled by the
    16→ * session layer above the orchestrator.
    17→ *
    18→ * ## Thread Safety
    19→ * All mutations must be performed by the orchestrator's sequential async
    20→ * pipeline. No concurrent writes are safe.
    21→ */
    22→
    23→import type { Timestamp, Nullable, SessionId, CampaignId } from '../types/index.js';
    24→import type { ConversationTurn } from './ConversationTurn.js';
    25→import type { CampaignSnapshot } from '../session/index.js';
    26→import type { KnowledgeSnapshot } from '../runtime/RuntimeContext.js';
    27→
    28→/**
    29→ * A registered tool available to the LLM in the current context.
    30→ */
    31→export interface ToolDefinition {
    32→  readonly name: string;
    33→  readonly description: string;
    34→  readonly parametersSchema: Readonly<Record<string, unknown>>;
    35→}
    36→
    37→/**
    38→ * A pending tool call from the LLM awaiting a result submission.
    39→ */
    40→export interface PendingToolCall {
    41→  readonly callId: string;
    42→  readonly toolName: string;
    43→  readonly argumentsJson: string;
    44→  readonly receivedAt: Timestamp;
    45→}
    46→
    47→/**
    48→ * A summarised representation of a completed turn stored in conversation memory.
    49→ */
    50→export interface TurnMemoryEntry {
    51→  readonly turnIndex: number;
    52→  readonly userTranscript: Nullable<string>;
    53→  readonly assistantResponse: Nullable<string>;
    54→  readonly completedAt: Nullable<Timestamp>;
    55→  readonly wasInterrupted: boolean;
    56→}
    57→
    58→/**
    59→ * The mutable context object owned by one `ConversationOrchestrator`.
    60→ */
    61→export class ConversationContext {
    62→  /** Unique identifier of the session this conversation belongs to. */
    63→  readonly sessionId: SessionId;
    64→
    65→  /** Campaign this conversation is executing. */
    66→  readonly campaignId: CampaignId;
    67→
    68→  /** Frozen campaign configuration snapshot. */
    69→  readonly campaign: Readonly<CampaignSnapshot>;
    70→
    71→  /** Frozen knowledge base snapshot for this campaign. */
    72→  readonly knowledge: Readonly<KnowledgeSnapshot>;
    73→
    74→  /** Conversation start timestamp. */
    75→  readonly startedAt: Timestamp;
    76→
    77→  private _currentTurn: Nullable<ConversationTurn> = null;
    78→  private _previousTurn: Nullable<ConversationTurn> = null;
    79→  private _history: TurnMemoryEntry[] = [];
    80→  private _instructions: string;
    81→  private _tools: ToolDefinition[] = [];
    82→  private _pendingToolCalls: Map<string, PendingToolCall> = new Map();
    83→  private _completedTurnCount = 0;
    84→  private _lastActivityAt: Timestamp;
    85→
    86→  constructor(
    87→    sessionId: SessionId,
    88→    campaignId: CampaignId,
    89→    campaign: Readonly<CampaignSnapshot>,
    90→    knowledge: Readonly<KnowledgeSnapshot>,
    91→    initialInstructions: string,
    92→    now: Timestamp
    93→  ) {
    94→    this.sessionId = sessionId;
    95→    this.campaignId = campaignId;
    96→    this.campaign = campaign;
    97→    this.knowledge = knowledge;
    98→    this._instructions = initialInstructions;
    99→    this.startedAt = now;
   100→    this._lastActivityAt = now;
   101→  }
   102→
   103→  // ─── Turn Management ──────────────────────────────────────────────────────
   104→
   105→  /**
   106→   * The turn currently being processed. Null between turns.
   107→   */
   108→  get currentTurn(): Nullable<ConversationTurn> {
   109→    return this._currentTurn;
   110→  }
   111→
   112→  /**
   113→   * The turn that completed immediately before the current one.
   114→   */
   115→  get previousTurn(): Nullable<ConversationTurn> {
   116→    return this._previousTurn;
   117→  }
   118→
   119→  /**
   120→   * Total number of turns that have reached a terminal state.
   121→   */
   122→  get completedTurnCount(): number {
   123→    return this._completedTurnCount;
   124→  }
   125→
   126→  /**
   127→   * Sets the current active turn. The previous turn is not modified here;
   128→   * call `archiveTurn()` to rotate turns on completion.
   129→   */
   130→  setCurrentTurn(turn: ConversationTurn): void {
   131→    this._currentTurn = turn;
   132→  }
   133→
   134→  /**
   135→   * Moves the current turn to `previousTurn`, increments the completed count,
   136→   * appends a memory entry, and clears `currentTurn`.
   137→   */
   138→  archiveTurn(completedTurn: ConversationTurn, now: Timestamp): void {
   139→    const entry: TurnMemoryEntry = {
   140→      turnIndex: completedTurn.turnIndex,
   141→      userTranscript: completedTurn.transcript,
   142→      assistantResponse: completedTurn.response,
   143→      completedAt: completedTurn.completedAt,
   144→      wasInterrupted: completedTurn.interruptions.length > 0,
   145→    };
   146→    this._history.push(entry);
   147→    this._previousTurn = completedTurn;
   148→    this._currentTurn = null;
   149→    this._completedTurnCount += 1;
   150→    this._lastActivityAt = now;
   151→  }
   152→
   153→  // ─── Conversation Memory ──────────────────────────────────────────────────
   154→
   155→  /**
   156→   * Ordered history of completed turns, oldest first.
   157→   */
   158→  get history(): readonly TurnMemoryEntry[] {
   159→    return this._history;
   160→  }
   161→
   162→  // ─── Instructions ─────────────────────────────────────────────────────────
   163→
   164→  /**
   165→   * The current system instructions sent to the LLM provider.
   166→   */
   167→  get instructions(): string {
   168→    return this._instructions;
   169→  }
   170→
   171→  /**
   172→   * Replaces the active instructions (e.g. dynamic prompt updates mid-call).
   173→   */
   174→  updateInstructions(instructions: string, now: Timestamp): void {
   175→    this._instructions = instructions;
   176→    this._lastActivityAt = now;
   177→  }
   178→
   179→  // ─── Tool Context ─────────────────────────────────────────────────────────
   180→
   181→  /**
   182→   * Tools currently registered for this conversation.
   183→   */
   184→  get tools(): readonly ToolDefinition[] {
   185→    return this._tools;
   186→  }
   187→
   188→  /**
   189→   * Replaces the set of available tools.
   190→   */
   191→  setTools(tools: readonly ToolDefinition[], now: Timestamp): void {
   192→    this._tools = [...tools];
   193→    this._lastActivityAt = now;
   194→  }
   195→
   196→  /**
   197→   * Records a pending tool call awaiting a result.
   198→   */
   199→  addPendingToolCall(call: PendingToolCall): void {
   200→    this._pendingToolCalls.set(call.callId, call);
   201→  }
   202→
   203→  /**
   204→   * Returns and removes a pending tool call by callId, or null if not found.
   205→   */
   206→  consumePendingToolCall(callId: string): Nullable<PendingToolCall> {
   207→    const call = this._pendingToolCalls.get(callId) ?? null;
   208→    if (call) this._pendingToolCalls.delete(callId);
   209→    return call;
   210→  }
   211→
   212→  /**
   213→   * All pending tool calls awaiting results.
   214→   */
   215→  get pendingToolCalls(): readonly PendingToolCall[] {
   216→    return Array.from(this._pendingToolCalls.values());
   217→  }
   218→
   219→  // ─── Activity ─────────────────────────────────────────────────────────────
   220→
   221→  /**
   222→   * Timestamp of the most recent state change in this context.
   223→   */
   224→  get lastActivityAt(): Timestamp {
   225→    return this._lastActivityAt;
   226→  }
   227→
   228→  /**
   229→   * Updates the last activity timestamp. Call whenever external audio or
   230→   * events arrive.
   231→   */
   232→  touch(now: Timestamp): void {
   233→    this._lastActivityAt = now;
   234→  }
   235→}
