/**
 * @module ConversationStage
 *
 * Defines every valid stage in the AI sales conversation lifecycle, the
 * allowed transitions between them, and metadata associated with each stage.
 *
 * ## Design principle
 * The stage graph is the single source of truth for what transitions are
 * legal.  No other module may permit a transition that is not declared here.
 */

// ─── Stage Enum ───────────────────────────────────────────────────────────────

export enum ConversationStage {
  GREETING          = 'GREETING',
  RAPPORT           = 'RAPPORT',
  DISCOVERY         = 'DISCOVERY',
  QUALIFICATION     = 'QUALIFICATION',
  PRESENTATION      = 'PRESENTATION',
  OBJECTION_HANDLING = 'OBJECTION_HANDLING',
  CLOSING           = 'CLOSING',
  CALL_COMPLETED    = 'CALL_COMPLETED',
}

// ─── Stage Metadata ───────────────────────────────────────────────────────────

export interface StageMetadata {
  /** Human-readable label for the stage. */
  readonly label: string;
  /**
   * Recommended minimum number of agent turns before advancing.
   * 0 means the stage can be skipped immediately if conditions are met.
   */
  readonly minTurns: number;
  /** Whether this stage is a terminal state (no further transitions). */
  readonly isTerminal: boolean;
  /** Brief description of the stage's purpose. */
  readonly description: string;
}

export const STAGE_METADATA: Readonly<Record<ConversationStage, StageMetadata>> = {
  [ConversationStage.GREETING]: {
    label: 'Greeting',
    minTurns: 1,
    isTerminal: false,
    description: 'Warm introduction and opening question.',
  },
  [ConversationStage.RAPPORT]: {
    label: 'Rapport',
    minTurns: 1,
    isTerminal: false,
    description: 'Build genuine connection before any business discussion.',
  },
  [ConversationStage.DISCOVERY]: {
    label: 'Discovery',
    minTurns: 2,
    isTerminal: false,
    description: 'Understand the customer\'s current situation and pain points.',
  },
  [ConversationStage.QUALIFICATION]: {
    label: 'Qualification',
    minTurns: 1,
    isTerminal: false,
    description: 'Confirm budget, authority, need, and timeline.',
  },
  [ConversationStage.PRESENTATION]: {
    label: 'Presentation',
    minTurns: 1,
    isTerminal: false,
    description: 'Present the relevant solution tied to discovered pain.',
  },
  [ConversationStage.OBJECTION_HANDLING]: {
    label: 'Objection Handling',
    minTurns: 0,
    isTerminal: false,
    description: 'Acknowledge and address customer concerns.',
  },
  [ConversationStage.CLOSING]: {
    label: 'Closing',
    minTurns: 1,
    isTerminal: false,
    description: 'Summarise, confirm next step, and thank the customer.',
  },
  [ConversationStage.CALL_COMPLETED]: {
    label: 'Call Completed',
    minTurns: 0,
    isTerminal: true,
    description: 'Conversation has ended; no further transitions are possible.',
  },
};

// ─── Allowed Transitions ──────────────────────────────────────────────────────

/**
 * Defines which stages can be transitioned to from each source stage.
 *
 * Rules:
 * - Forward-only movement through the funnel (primary path).
 * - Objection handling can be entered from DISCOVERY, QUALIFICATION,
 *   PRESENTATION, or CLOSING, and exits back to the originating stage.
 * - Any non-terminal stage can transition directly to CALL_COMPLETED
 *   (call dropped, customer hangs up, hard stop).
 */
export const ALLOWED_TRANSITIONS: Readonly<Record<ConversationStage, readonly ConversationStage[]>> = {
  [ConversationStage.GREETING]: [
    ConversationStage.RAPPORT,
    ConversationStage.DISCOVERY,        // skip rapport if customer is direct
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.RAPPORT]: [
    ConversationStage.DISCOVERY,
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.DISCOVERY]: [
    ConversationStage.QUALIFICATION,
    ConversationStage.OBJECTION_HANDLING,
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.QUALIFICATION]: [
    ConversationStage.PRESENTATION,
    ConversationStage.OBJECTION_HANDLING,
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.PRESENTATION]: [
    ConversationStage.OBJECTION_HANDLING,
    ConversationStage.CLOSING,
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.OBJECTION_HANDLING]: [
    ConversationStage.DISCOVERY,        // resurface pain after objection
    ConversationStage.QUALIFICATION,
    ConversationStage.PRESENTATION,
    ConversationStage.CLOSING,
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.CLOSING]: [
    ConversationStage.OBJECTION_HANDLING, // last-minute objection
    ConversationStage.CALL_COMPLETED,
  ],
  [ConversationStage.CALL_COMPLETED]: [],
};

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Returns true if `to` is an allowed successor of `from`.
 */
export function isTransitionAllowed(
  from: ConversationStage,
  to: ConversationStage
): boolean {
  return (ALLOWED_TRANSITIONS[from] as readonly ConversationStage[]).includes(to);
}

/**
 * Returns the list of stages reachable from `stage`.
 */
export function getReachableStages(stage: ConversationStage): readonly ConversationStage[] {
  return ALLOWED_TRANSITIONS[stage];
}

/**
 * Returns true if `stage` is a terminal state.
 */
export function isTerminalStage(stage: ConversationStage): boolean {
  return STAGE_METADATA[stage].isTerminal;
}

/**
 * Ordered forward progression of the main sales funnel (excluding terminals).
 */
export const FUNNEL_ORDER: readonly ConversationStage[] = [
  ConversationStage.GREETING,
  ConversationStage.RAPPORT,
  ConversationStage.DISCOVERY,
  ConversationStage.QUALIFICATION,
  ConversationStage.PRESENTATION,
  ConversationStage.OBJECTION_HANDLING,
  ConversationStage.CLOSING,
  ConversationStage.CALL_COMPLETED,
];

/**
 * @module ConversationMemory
 *
 * Tracks all customer-specific information gathered during a conversation.
 *
 * ## Purpose
 * Acts as the AI's working memory for one call — everything the agent has
 * learned about the customer is stored here so it can be referenced when
 * evaluating the next action, advancing the state machine, or generating
 * a closing summary.
 *
 * ## Ownership
 * Created by `ConversationStateFactory` and mutated exclusively through its
 * public update methods.  The state machine reads it; only external callers
 * (orchestrator, evaluator) write to it via the update API.
 *
 * ## No AI imports
 * Pure data container — no OpenAI, Exotel, or prompt logic.
 */

// ─── Sub-types ────────────────────────────────────────────────────────────────

/**
 * A single objection raised by the customer.
 */
export interface CustomerObjection {
  /** Short label for this objection. */
  readonly topic: string;
  /** The customer's verbatim phrasing, if captured. */
  readonly verbatim?: string;
  /** Whether the agent has addressed this objection. */
  resolved: boolean;
  /** ISO timestamp when the objection was first raised. */
  readonly raisedAt: string;
}

/**
 * A commitment or agreement made during the call.
 */
export interface CallCommitment {
  /** Description of what was agreed. */
  readonly description: string;
  /** ISO timestamp when the commitment was made. */
  readonly agreedAt: string;
}

// ─── ConversationMemory ───────────────────────────────────────────────────────

/**
 * All customer data gathered during the conversation.
 * Fields are optional because information arrives incrementally.
 */
export class ConversationMemory {
  // ── Identity ───────────────────────────────────────────────────────────────
  private _customerName?: string;
  private _company?: string;

  // ── Intent & Need ──────────────────────────────────────────────────────────
  private _intent?: string;
  private _painPoints: string[] = [];

  // ── Qualification Data ─────────────────────────────────────────────────────
  private _budget?: string;
  private _timeline?: string;
  private _isDecisionMaker?: boolean;

  // ── Objections & Commitments ───────────────────────────────────────────────
  private _objections: CustomerObjection[] = [];
  private _commitments: CallCommitment[] = [];

  // ── Next Action ────────────────────────────────────────────────────────────
  private _nextAction?: string;

  // ─── Identity ──────────────────────────────────────────────────────────────

  get customerName(): string | undefined { return this._customerName; }
  get company(): string | undefined { return this._company; }

  setCustomerName(name: string): void { this._customerName = name.trim(); }
  setCompany(company: string): void { this._company = company.trim(); }

  // ─── Intent & Need ─────────────────────────────────────────────────────────

  get intent(): string | undefined { return this._intent; }
  get painPoints(): readonly string[] { return this._painPoints; }

  setIntent(intent: string): void { this._intent = intent.trim(); }

  addPainPoint(point: string): void {
    const trimmed = point.trim();
    if (trimmed && !this._painPoints.includes(trimmed)) {
      this._painPoints.push(trimmed);
    }
  }

  // ─── Qualification ─────────────────────────────────────────────────────────

  get budget(): string | undefined { return this._budget; }
  get timeline(): string | undefined { return this._timeline; }
  get isDecisionMaker(): boolean | undefined { return this._isDecisionMaker; }

  setBudget(budget: string): void { this._budget = budget.trim(); }
  setTimeline(timeline: string): void { this._timeline = timeline.trim(); }
  setIsDecisionMaker(value: boolean): void { this._isDecisionMaker = value; }

  // ─── Objections ────────────────────────────────────────────────────────────

  get objections(): readonly CustomerObjection[] { return this._objections; }

  get unresolvedObjections(): readonly CustomerObjection[] {
    return this._objections.filter((o) => !o.resolved);
  }

  get hasUnresolvedObjections(): boolean {
    return this.unresolvedObjections.length > 0;
  }

  addObjection(topic: string, verbatim?: string): void {
    const already = this._objections.find(
      (o) => o.topic.toLowerCase() === topic.toLowerCase()
    );
    if (!already) {
      this._objections.push({
        topic,
        verbatim,
        resolved: false,
        raisedAt: new Date().toISOString(),
      });
    }
  }

  resolveObjection(topic: string): boolean {
    const obj = this._objections.find(
      (o) => o.topic.toLowerCase() === topic.toLowerCase()
    );
    if (obj) {
      obj.resolved = true;
      return true;
    }
    return false;
  }

  // ─── Commitments ───────────────────────────────────────────────────────────

  get commitments(): readonly CallCommitment[] { return this._commitments; }

  addCommitment(description: string): void {
    this._commitments.push({
      description: description.trim(),
      agreedAt: new Date().toISOString(),
    });
  }

  // ─── Next Action ───────────────────────────────────────────────────────────

  get nextAction(): string | undefined { return this._nextAction; }
  setNextAction(action: string): void { this._nextAction = action.trim(); }

  // ─── Derived Helpers ───────────────────────────────────────────────────────

  /**
   * True when enough qualification data has been gathered to present a solution.
   */
  get isQualified(): boolean {
    return (
      this._painPoints.length > 0 &&
      this._isDecisionMaker !== undefined
    );
  }

  /**
   * True when a next action has been committed to.
   */
  get hasNextAction(): boolean {
    return !!this._nextAction;
  }

  /**
   * Serialises the memory to a plain object for logging or persistence.
   */
  toSnapshot(): Readonly<Record<string, unknown>> {
    return Object.freeze({
      customerName: this._customerName,
      company: this._company,
      intent: this._intent,
      painPoints: [...this._painPoints],
      budget: this._budget,
      timeline: this._timeline,
      isDecisionMaker: this._isDecisionMaker,
      objections: this._objections.map((o) => ({ ...o })),
      commitments: this._commitments.map((c) => ({ ...c })),
      nextAction: this._nextAction,
    });
  }
}

/**
 * @module ConversationProgress
 *
 * Tracks quantitative progress metrics for the current conversation.
 *
 * ## Purpose
 * Maintains per-stage and overall counters — agent turns, questions asked,
 * interruptions, and time spent — so the evaluator and state machine can
 * make data-driven decisions (e.g. "has the minimum turn count been met?").
 *
 * ## Ownership
 * Created alongside `ConversationState` and mutated by the state machine
 * as turns arrive.  Read-only outside the state machine.
 *
 * ## No AI imports
 * Pure metrics container — no OpenAI, Exotel, or prompt logic.
 */

import type { ConversationStage } from './ConversationStage.js';

// ─── Per-Stage Stats ──────────────────────────────────────────────────────────

export interface StageStats {
  /** Number of completed agent turns in this stage. */
  agentTurns: number;
  /** Number of questions the agent asked in this stage. */
  questionsAsked: number;
  /** Number of times the customer interrupted the agent in this stage. */
  interruptions: number;
  /** Epoch ms when this stage was entered. */
  enteredAt: number;
  /** Epoch ms when this stage was exited, or null if still active. */
  exitedAt: number | null;
}

// ─── ConversationProgress ─────────────────────────────────────────────────────

export class ConversationProgress {
  private readonly _stageStats: Map<ConversationStage, StageStats> = new Map();

  /** Wall-clock epoch ms when the entire conversation started. */
  readonly conversationStartedAt: number;

  /** Total agent turns across all stages. */
  private _totalAgentTurns = 0;

  /** Total questions asked across all stages. */
  private _totalQuestionsAsked = 0;

  /** Total interruptions across all stages. */
  private _totalInterruptions = 0;

  constructor(startedAt: number = Date.now()) {
    this.conversationStartedAt = startedAt;
  }

  // ─── Stage Lifecycle ────────────────────────────────────────────────────────

  /**
   * Records entry into a stage — initialises its stats block.
   * Safe to call multiple times for the same stage (re-entry after objection
   * handling will accumulate rather than reset).
   */
  enterStage(stage: ConversationStage, now: number = Date.now()): void {
    if (!this._stageStats.has(stage)) {
      this._stageStats.set(stage, {
        agentTurns: 0,
        questionsAsked: 0,
        interruptions: 0,
        enteredAt: now,
        exitedAt: null,
      });
    }
  }

  /**
   * Records exit from a stage, sealing its elapsed time.
   */
  exitStage(stage: ConversationStage, now: number = Date.now()): void {
    const stats = this._stageStats.get(stage);
    if (stats) {
      stats.exitedAt = now;
    }
  }

  // ─── Turn & Event Recording ─────────────────────────────────────────────────

  /**
   * Records one completed agent turn in the given stage.
   */
  recordAgentTurn(stage: ConversationStage): void {
    const stats = this._ensureStage(stage);
    stats.agentTurns += 1;
    this._totalAgentTurns += 1;
  }

  /**
   * Records a question asked by the agent in the given stage.
   */
  recordQuestion(stage: ConversationStage): void {
    const stats = this._ensureStage(stage);
    stats.questionsAsked += 1;
    this._totalQuestionsAsked += 1;
  }

  /**
   * Records a customer interruption in the given stage.
   */
  recordInterruption(stage: ConversationStage): void {
    const stats = this._ensureStage(stage);
    stats.interruptions += 1;
    this._totalInterruptions += 1;
  }

  // ─── Readers ────────────────────────────────────────────────────────────────

  get totalAgentTurns(): number { return this._totalAgentTurns; }
  get totalQuestionsAsked(): number { return this._totalQuestionsAsked; }
  get totalInterruptions(): number { return this._totalInterruptions; }

  /**
   * Stats for a specific stage, or null if that stage has not been entered.
   */
  getStageStats(stage: ConversationStage): Readonly<StageStats> | null {
    return this._stageStats.get(stage) ?? null;
  }

  /**
   * Number of completed agent turns in a specific stage.
   */
  turnsInStage(stage: ConversationStage): number {
    return this._stageStats.get(stage)?.agentTurns ?? 0;
  }

  /**
   * Number of questions asked in a specific stage.
   */
  questionsInStage(stage: ConversationStage): number {
    return this._stageStats.get(stage)?.questionsAsked ?? 0;
  }

  /**
   * Milliseconds elapsed in a specific stage.
   * Returns elapsed-to-now if the stage has not yet exited.
   */
  timeInStage(stage: ConversationStage, now: number = Date.now()): number {
    const stats = this._stageStats.get(stage);
    if (!stats) return 0;
    return (stats.exitedAt ?? now) - stats.enteredAt;
  }

  /**
   * Total elapsed milliseconds since the conversation started.
   */
  totalElapsedMs(now: number = Date.now()): number {
    return now - this.conversationStartedAt;
  }

  /**
   * Ordered list of stages that have been entered (in entry order).
   */
  get visitedStages(): readonly ConversationStage[] {
    return Array.from(this._stageStats.keys());
  }

  /**
   * Serialises all progress metrics to a plain object for logging.
   */
  toSnapshot(now: number = Date.now()): Readonly<Record<string, unknown>> {
    const stageBreakdown: Record<string, unknown> = {};
    for (const [stage, stats] of this._stageStats) {
      stageBreakdown[stage] = {
        ...stats,
        elapsedMs: (stats.exitedAt ?? now) - stats.enteredAt,
      };
    }
    return Object.freeze({
      conversationStartedAt: this.conversationStartedAt,
      totalElapsedMs: this.totalElapsedMs(now),
      totalAgentTurns: this._totalAgentTurns,
      totalQuestionsAsked: this._totalQuestionsAsked,
      totalInterruptions: this._totalInterruptions,
      stages: stageBreakdown,
    });
  }

  // ─── Private Helpers ────────────────────────────────────────────────────────

  private _ensureStage(stage: ConversationStage): StageStats {
    if (!this._stageStats.has(stage)) {
      this.enterStage(stage);
    }
    return this._stageStats.get(stage)!;
  }
}

/**
 * @module ConversationSignals
 *
 * Defines the typed signals (inputs) that drive state machine transitions.
 *
 * ## Purpose
 * Every event that can change conversation state — a customer utterance, an
 * agent turn completing, silence timeout, call drop, etc. — is modelled as a
 * typed `ConversationSignal`.  The state machine accepts only these signals;
 * it never reads raw audio or network events directly.
 *
 * ## Design principle
 * Signals are the boundary between the outside world and the state engine.
 * They carry only the semantic payload needed for a transition decision.
 * No AI imports, no transport types.
 */

import type { ConversationStage } from './ConversationStage.js';

// ─── Signal Discriminant ──────────────────────────────────────────────────────

export type SignalType =
  | 'AGENT_TURN_COMPLETED'
  | 'QUESTION_ASKED'
  | 'CUSTOMER_RESPONDED'
  | 'CUSTOMER_INTERRUPTED'
  | 'CUSTOMER_SILENT'
  | 'OBJECTION_RAISED'
  | 'OBJECTION_RESOLVED'
  | 'PAIN_POINT_IDENTIFIED'
  | 'QUALIFICATION_DATA_GATHERED'
  | 'COMMITMENT_MADE'
  | 'ADVANCE_STAGE'
  | 'FORCE_STAGE'
  | 'CALL_ENDED';

// ─── Signal Payloads ──────────────────────────────────────────────────────────

/** Agent finished speaking a response turn. */
export interface AgentTurnCompletedSignal {
  type: 'AGENT_TURN_COMPLETED';
  /** Whether the agent's turn included a question. */
  containedQuestion: boolean;
}

/** Agent explicitly asked a question. */
export interface QuestionAskedSignal {
  type: 'QUESTION_ASKED';
}

/** Customer produced a meaningful utterance. */
export interface CustomerRespondedSignal {
  type: 'CUSTOMER_RESPONDED';
  /** Approximate sentiment of the response. */
  sentiment?: 'positive' | 'neutral' | 'negative';
  /** True if the response indicated readiness to advance. */
  showedIntent?: boolean;
}

/** Customer interrupted the agent mid-response. */
export interface CustomerInterruptedSignal {
  type: 'CUSTOMER_INTERRUPTED';
}

/** Customer was silent past the configured threshold. */
export interface CustomerSilentSignal {
  type: 'CUSTOMER_SILENT';
  /** Duration of silence in milliseconds. */
  durationMs: number;
}

/** Customer raised an objection. */
export interface ObjectionRaisedSignal {
  type: 'OBJECTION_RAISED';
  topic: string;
  verbatim?: string;
}

/** An objection was successfully addressed. */
export interface ObjectionResolvedSignal {
  type: 'OBJECTION_RESOLVED';
  topic: string;
}

/** A customer pain point was identified. */
export interface PainPointIdentifiedSignal {
  type: 'PAIN_POINT_IDENTIFIED';
  description: string;
}

/** Qualification data was gathered (budget, timeline, decision-maker). */
export interface QualificationDataGatheredSignal {
  type: 'QUALIFICATION_DATA_GATHERED';
  field: 'budget' | 'timeline' | 'decisionMaker';
  value: string | boolean;
}

/** Customer made a commitment (e.g. agreed to demo). */
export interface CommitmentMadeSignal {
  type: 'COMMITMENT_MADE';
  description: string;
}

/**
 * Requests an automatic advance to the next logical stage in the funnel.
 * The state machine will validate the transition before allowing it.
 */
export interface AdvanceStageSignal {
  type: 'ADVANCE_STAGE';
}

/**
 * Forces a transition to a specific stage.
 * The state machine still validates that the target is reachable.
 */
export interface ForceStageSignal {
  type: 'FORCE_STAGE';
  targetStage: ConversationStage;
  reason: string;
}

/** Call ended — moves to CALL_COMPLETED regardless of current stage. */
export interface CallEndedSignal {
  type: 'CALL_ENDED';
  reason: 'customer_hangup' | 'agent_closed' | 'timeout' | 'error';
}

// ─── Union Type ───────────────────────────────────────────────────────────────

export type ConversationSignal =
  | AgentTurnCompletedSignal
  | QuestionAskedSignal
  | CustomerRespondedSignal
  | CustomerInterruptedSignal
  | CustomerSilentSignal
  | ObjectionRaisedSignal
  | ObjectionResolvedSignal
  | PainPointIdentifiedSignal
  | QualificationDataGatheredSignal
  | CommitmentMadeSignal
  | AdvanceStageSignal
  | ForceStageSignal
  | CallEndedSignal;

// ─── Signal Factories (convenience constructors) ──────────────────────────────

export const Signals = {
  agentTurnCompleted: (containedQuestion: boolean): AgentTurnCompletedSignal => ({
    type: 'AGENT_TURN_COMPLETED',
    containedQuestion,
  }),
  questionAsked: (): QuestionAskedSignal => ({ type: 'QUESTION_ASKED' }),
  customerResponded: (
    sentiment?: CustomerRespondedSignal['sentiment'],
    showedIntent?: boolean
  ): CustomerRespondedSignal => ({
    type: 'CUSTOMER_RESPONDED',
    sentiment,
    showedIntent,
  }),
  customerInterrupted: (): CustomerInterruptedSignal => ({ type: 'CUSTOMER_INTERRUPTED' }),
  customerSilent: (durationMs: number): CustomerSilentSignal => ({ type: 'CUSTOMER_SILENT', durationMs }),
  objectionRaised: (topic: string, verbatim?: string): ObjectionRaisedSignal => ({
    type: 'OBJECTION_RAISED', topic, verbatim,
  }),
  objectionResolved: (topic: string): ObjectionResolvedSignal => ({ type: 'OBJECTION_RESOLVED', topic }),
  painPointIdentified: (description: string): PainPointIdentifiedSignal => ({
    type: 'PAIN_POINT_IDENTIFIED', description,
  }),
  qualificationData: (
    field: QualificationDataGatheredSignal['field'],
    value: string | boolean
  ): QualificationDataGatheredSignal => ({
    type: 'QUALIFICATION_DATA_GATHERED', field, value,
  }),
  commitmentMade: (description: string): CommitmentMadeSignal => ({
    type: 'COMMITMENT_MADE', description,
  }),
  advanceStage: (): AdvanceStageSignal => ({ type: 'ADVANCE_STAGE' }),
  forceStage: (targetStage: ConversationStage, reason: string): ForceStageSignal => ({
    type: 'FORCE_STAGE', targetStage, reason,
  }),
  callEnded: (reason: CallEndedSignal['reason']): CallEndedSignal => ({
    type: 'CALL_ENDED', reason,
  }),
} as const;

/**
 * @module ConversationState
 *
 * Immutable snapshot of the conversation's current state at any point in time.
 *
 * ## Purpose
 * Represents the full observable state of one conversation — stage, history,
 * progress metrics, and memory — at a single instant.  The state machine
 * produces a new `ConversationState` on every transition; the previous
 * snapshot is never mutated.
 *
 * ## Ownership
 * Only `ConversationStateMachine` may produce `ConversationState` instances.
 * Consumers (orchestrator, evaluator) always read via the state machine's
 * `currentState` property.
 *
 * ## No AI imports
 * Pure state data — no OpenAI, Exotel, or prompt logic.
 */

import type { ConversationStage } from './ConversationStage.js';
import { STAGE_METADATA, isTerminalStage, ALLOWED_TRANSITIONS } from './ConversationStage.js';
import type { ConversationMemory } from './ConversationMemory.js';
import type { ConversationProgress } from './ConversationProgress.js';

// ─── ConversationState ────────────────────────────────────────────────────────

export class ConversationState {
  /** The stage the conversation is currently in. */
  readonly currentStage: ConversationStage;

  /** The stage the conversation was in immediately before the current one. */
  readonly previousStage: ConversationStage | null;

  /** Full ordered history of every stage visited (including re-visits). */
  readonly stageHistory: readonly ConversationStage[];

  /** Epoch ms when the current stage was entered. */
  readonly stageEnteredAt: number;

  /** Epoch ms when this state snapshot was created. */
  readonly snapshotAt: number;

  /** Reference to the live memory object (read-only from state consumers). */
  readonly memory: Readonly<ConversationMemory>;

  /** Reference to the live progress tracker (read-only from state consumers). */
  readonly progress: Readonly<ConversationProgress>;

  constructor(params: {
    currentStage: ConversationStage;
    previousStage: ConversationStage | null;
    stageHistory: readonly ConversationStage[];
    stageEnteredAt: number;
    snapshotAt: number;
    memory: ConversationMemory;
    progress: ConversationProgress;
  }) {
    this.currentStage = params.currentStage;
    this.previousStage = params.previousStage;
    this.stageHistory = params.stageHistory;
    this.stageEnteredAt = params.stageEnteredAt;
    this.snapshotAt = params.snapshotAt;
    this.memory = params.memory;
    this.progress = params.progress;
  }

  // ─── Derived Properties ────────────────────────────────────────────────────

  /** True if the conversation has reached a terminal stage. */
  get isTerminal(): boolean {
    return isTerminalStage(this.currentStage);
  }

  /** Human-readable label for the current stage. */
  get currentStageLabel(): string {
    return STAGE_METADATA[this.currentStage].label;
  }

  /** Stages that can be transitioned to from the current stage. */
  get reachableStages(): readonly ConversationStage[] {
    return ALLOWED_TRANSITIONS[this.currentStage];
  }

  /** Whether any forward transition is possible. */
  get canAdvance(): boolean {
    return this.reachableStages.length > 0;
  }

  /**
   * Milliseconds spent in the current stage up to `now`.
   */
  timeInCurrentStage(now: number = Date.now()): number {
    return now - this.stageEnteredAt;
  }

  /**
   * Number of completed agent turns in the current stage.
   */
  get turnsInCurrentStage(): number {
    return this.progress.turnsInStage(this.currentStage);
  }

  /**
   * Number of questions asked in the current stage.
   */
  get questionsInCurrentStage(): number {
    return this.progress.questionsInStage(this.currentStage);
  }

  /**
   * Whether the minimum turn count for the current stage has been met.
   */
  get hasMetMinimumTurns(): boolean {
    const min = STAGE_METADATA[this.currentStage].minTurns;
    return this.turnsInCurrentStage >= min;
  }

  /**
   * Whether there are any unresolved customer objections.
   */
  get hasUnresolvedObjections(): boolean {
    return this.memory.hasUnresolvedObjections;
  }

  /**
   * Serialises the state snapshot to a plain object for logging.
   */
  toSnapshot(): Readonly<Record<string, unknown>> {
    return Object.freeze({
      currentStage: this.currentStage,
      previousStage: this.previousStage,
      stageHistory: [...this.stageHistory],
      stageEnteredAt: this.stageEnteredAt,
      snapshotAt: this.snapshotAt,
      isTerminal: this.isTerminal,
      turnsInCurrentStage: this.turnsInCurrentStage,
      questionsInCurrentStage: this.questionsInCurrentStage,
      hasMetMinimumTurns: this.hasMetMinimumTurns,
      hasUnresolvedObjections: this.hasUnresolvedObjections,
      memory: this.memory.toSnapshot(),
      progress: this.progress.toSnapshot(),
    });
  }
}

/**
 * @module ConversationEvaluator
 *
 * Determines what the AI agent should do next given the current state.
 *
 * ## Purpose
 * The evaluator is the decision-making layer above the state machine.  It
 * reads the current `ConversationState` and returns an `AgentAction` — a
 * pure recommendation with no side effects.  The caller (orchestrator) is
 * responsible for acting on the recommendation.
 *
 * ## What it decides
 * - Should the agent ask another question?
 * - Should the agent explain / clarify?
 * - Should the agent summarise what has been learned?
 * - Should the agent attempt to close?
 * - Should the agent handle an objection?
 * - Should the agent advance to the next stage?
 *
 * ## Design principle
 * Pure function — no mutations, no I/O, no AI imports.
 * `evaluate()` is deterministic given the same state.
 */

import { ConversationStage, STAGE_METADATA } from './ConversationStage.js';
import type { ConversationState } from './ConversationState.js';

// ─── Agent Action Types ───────────────────────────────────────────────────────

export type AgentActionType =
  | 'ASK_QUESTION'
  | 'EXPLAIN'
  | 'SUMMARIZE'
  | 'HANDLE_OBJECTION'
  | 'ATTEMPT_CLOSE'
  | 'ADVANCE_STAGE'
  | 'RE_ENGAGE'    // customer silent / disengaged
  | 'WRAP_UP';     // call about to complete

/**
 * A structured recommendation produced by the evaluator.
 */
export interface AgentAction {
  /** The recommended next action type. */
  readonly action: AgentActionType;
  /** Confidence level for this recommendation (0–1). */
  readonly confidence: number;
  /** Human-readable rationale for the recommendation. */
  readonly rationale: string;
  /** Whether the state machine should advance stage after this action. */
  readonly shouldAdvanceStage: boolean;
}

// ─── Evaluation Config ────────────────────────────────────────────────────────

export interface EvaluatorConfig {
  /**
   * Maximum questions to ask in a single stage before forcing an advance.
   * @default 4
   */
  maxQuestionsPerStage: number;
  /**
   * Maximum milliseconds to spend in a single stage before forcing an advance.
   * @default 120_000 (2 minutes)
   */
  maxMsPerStage: number;
  /**
   * Minimum pain points needed before PRESENTATION is allowed.
   * @default 1
   */
  minPainPointsForPresentation: number;
}

export const DEFAULT_EVALUATOR_CONFIG: Readonly<EvaluatorConfig> = {
  maxQuestionsPerStage: 4,
  maxMsPerStage: 120_000,
  minPainPointsForPresentation: 1,
};

// ─── ConversationEvaluator ────────────────────────────────────────────────────

export class ConversationEvaluator {
  private readonly config: Readonly<EvaluatorConfig>;

  constructor(config: Partial<EvaluatorConfig> = {}) {
    this.config = Object.freeze({ ...DEFAULT_EVALUATOR_CONFIG, ...config });
  }

  /**
   * Evaluates the current conversation state and returns a recommended action.
   * Pure — no mutations, no async.
   */
  evaluate(state: ConversationState, now: number = Date.now()): AgentAction {
    // ── Terminal — wrap up ────────────────────────────────────────────────────
    if (state.isTerminal) {
      return this._action('WRAP_UP', 1, 'Conversation is in a terminal stage.', false);
    }

    // ── Unresolved objection — must handle before anything else ───────────────
    if (state.hasUnresolvedObjections && state.currentStage !== ConversationStage.OBJECTION_HANDLING) {
      return this._action(
        'HANDLE_OBJECTION',
        0.95,
        `There are ${state.memory.unresolvedObjections.length} unresolved objection(s). Transition to objection handling.`,
        true
      );
    }

    const timeInStage = state.timeInCurrentStage(now);
    const questionsInStage = state.questionsInCurrentStage;
    const minTurns = STAGE_METADATA[state.currentStage].minTurns;

    // ── Stage-specific evaluation ─────────────────────────────────────────────
    switch (state.currentStage) {
      case ConversationStage.GREETING:
        return this._evaluateGreeting(state);

      case ConversationStage.RAPPORT:
        return this._evaluateRapport(state, timeInStage, questionsInStage);

      case ConversationStage.DISCOVERY:
        return this._evaluateDiscovery(state, questionsInStage);

      case ConversationStage.QUALIFICATION:
        return this._evaluateQualification(state, questionsInStage);

      case ConversationStage.PRESENTATION:
        return this._evaluatePresentation(state, questionsInStage);

      case ConversationStage.OBJECTION_HANDLING:
        return this._evaluateObjectionHandling(state);

      case ConversationStage.CLOSING:
        return this._evaluateClosing(state);

      case ConversationStage.CALL_COMPLETED:
        return this._action('WRAP_UP', 1, 'Call is complete.', false);
    }

    // Exhaustive default
    return this._action('ASK_QUESTION', 0.5, 'Unknown stage — default to asking a question.', false);
  }

  // ─── Stage Evaluators ──────────────────────────────────────────────────────

  private _evaluateGreeting(state: ConversationState): AgentAction {
    if (state.turnsInCurrentStage === 0) {
      return this._action('ASK_QUESTION', 1, 'No turns yet — open with greeting and ice-breaker question.', false);
    }
    if (state.hasMetMinimumTurns) {
      return this._action('ADVANCE_STAGE', 0.9, 'Greeting complete — advance to rapport.', true);
    }
    return this._action('ASK_QUESTION', 0.8, 'Continue greeting — minimum turns not yet met.', false);
  }

  private _evaluateRapport(
    state: ConversationState,
    timeInStage: number,
    questionsInStage: number
  ): AgentAction {
    if (questionsInStage >= 2 || timeInStage > 30_000) {
      return this._action('ADVANCE_STAGE', 0.85, 'Rapport established — transition to discovery.', true);
    }
    return this._action('ASK_QUESTION', 0.9, 'Build rapport with an open question about the customer.', false);
  }

  private _evaluateDiscovery(
    state: ConversationState,
    questionsInStage: number
  ): AgentAction {
    const painPoints = state.memory.painPoints.length;
    const atLimit = questionsInStage >= this.config.maxQuestionsPerStage;

    if (painPoints >= this.config.minPainPointsForPresentation && state.hasMetMinimumTurns) {
      return this._action('ADVANCE_STAGE', 0.88, `${painPoints} pain point(s) found — ready for qualification.`, true);
    }
    if (atLimit) {
      return this._action(
        'SUMMARIZE',
        0.75,
        'Question limit reached in discovery — summarise findings before advancing.',
        true
      );
    }
    return this._action('ASK_QUESTION', 0.92, 'Continue discovering pain points.', false);
  }

  private _evaluateQualification(
    state: ConversationState,
    questionsInStage: number
  ): AgentAction {
    const { budget, timeline, isDecisionMaker } = state.memory;
    const qualified = budget !== undefined && timeline !== undefined && isDecisionMaker !== undefined;
    const atLimit = questionsInStage >= this.config.maxQuestionsPerStage;

    if (qualified) {
      return this._action('ADVANCE_STAGE', 0.9, 'All qualification data gathered — advance to presentation.', true);
    }
    if (atLimit) {
      return this._action(
        'SUMMARIZE',
        0.7,
        'Question limit reached in qualification — advance with partial data.',
        true
      );
    }
    // Determine which field to qualify next
    if (isDecisionMaker === undefined) {
      return this._action('ASK_QUESTION', 0.95, 'Decision-maker not confirmed — ask about authority.', false);
    }
    if (budget === undefined) {
      return this._action('ASK_QUESTION', 0.9, 'Budget not captured — ask about investment capacity.', false);
    }
    return this._action('ASK_QUESTION', 0.85, 'Timeline not captured — ask about urgency.', false);
  }

  private _evaluatePresentation(
    state: ConversationState,
    questionsInStage: number
  ): AgentAction {
    if (state.turnsInCurrentStage === 0) {
      return this._action('EXPLAIN', 0.95, 'Present the solution tied to the discovered pain.', false);
    }
    if (questionsInStage >= 1 && state.hasMetMinimumTurns) {
      return this._action('ATTEMPT_CLOSE', 0.8, 'Presentation delivered and reaction gauged — attempt close.', true);
    }
    return this._action('ASK_QUESTION', 0.85, 'Check reaction to presentation with a probing question.', false);
  }

  private _evaluateObjectionHandling(state: ConversationState): AgentAction {
    const unresolved = state.memory.unresolvedObjections;
    if (unresolved.length === 0) {
      return this._action('ADVANCE_STAGE', 0.9, 'All objections resolved — return to funnel.', true);
    }
    if (state.turnsInCurrentStage === 0) {
      return this._action('EXPLAIN', 0.95, `Address objection: "${unresolved[0].topic}".`, false);
    }
    return this._action('ASK_QUESTION', 0.8, 'Check whether the objection has been resolved to the customer\'s satisfaction.', false);
  }

  private _evaluateClosing(state: ConversationState): AgentAction {
    if (!state.memory.hasNextAction) {
      return this._action('SUMMARIZE', 0.9, 'Summarise conversation and propose a concrete next step.', false);
    }
    if (state.memory.commitments.length > 0) {
      return this._action('WRAP_UP', 0.95, 'Commitment made and next action confirmed — wrap up gracefully.', true);
    }
    return this._action('ATTEMPT_CLOSE', 0.85, 'Next action set but commitment not yet confirmed — solidify.', false);
  }

  // ─── Helpers ────────────────────────────────────────────────────────────────

  private _action(
    action: AgentActionType,
    confidence: number,
    rationale: string,
    shouldAdvanceStage: boolean
  ): AgentAction {
    return Object.freeze({ action, confidence, rationale, shouldAdvanceStage });
  }
}

/**
 * @module ConversationStateMachine
 *
 * Manages conversation stage transitions, enforcing the allowed-transition
 * graph defined in ConversationStage and updating progress metrics.
 *
 * ## Purpose
 * The single authoritative controller for conversation progression.  All
 * stage changes flow through `dispatch()`.  Consumers never mutate stage
 * directly.
 *
 * ## Guarantees
 * - Transitions are validated against `ALLOWED_TRANSITIONS` before applying.
 * - Progress and memory are updated atomically with state transitions.
 * - Every transition is appended to an immutable audit log.
 * - Terminal stages reject all further transitions gracefully.
 *
 * ## No AI imports
 * Pure state machine — no OpenAI, Exotel, or prompt logic.
 */

import {
  ConversationStage,
  isTransitionAllowed,
  isTerminalStage,
  FUNNEL_ORDER,
} from './ConversationStage.js';
import type { ConversationSignal } from './ConversationSignals.js';
import { ConversationState } from './ConversationState.js';
import type { ConversationMemory } from './ConversationMemory.js';
import type { ConversationProgress } from './ConversationProgress.js';

// ─── Transition Record ────────────────────────────────────────────────────────

export interface TransitionRecord {
  readonly from: ConversationStage;
  readonly to: ConversationStage;
  readonly signal: ConversationSignal;
  readonly occurredAt: number;
}

// ─── Transition Error ─────────────────────────────────────────────────────────

export class TransitionError extends Error {
  constructor(
    from: ConversationStage,
    to: ConversationStage,
    reason: string
  ) {
    super(`Invalid transition ${from} → ${to}: ${reason}`);
    this.name = 'TransitionError';
  }
}

// ─── ConversationStateMachine ─────────────────────────────────────────────────

export class ConversationStateMachine {
  private _currentStage: ConversationStage;
  private _previousStage: ConversationStage | null = null;
  private _stageHistory: ConversationStage[] = [];
  private _stageEnteredAt: number;
  private readonly _transitionLog: TransitionRecord[] = [];

  private readonly _memory: ConversationMemory;
  private readonly _progress: ConversationProgress;

  constructor(
    initialStage: ConversationStage,
    memory: ConversationMemory,
    progress: ConversationProgress,
    now: number = Date.now()
  ) {
    this._currentStage = initialStage;
    this._stageHistory.push(initialStage);
    this._stageEnteredAt = now;
    this._memory = memory;
    this._progress = progress;
    this._progress.enterStage(initialStage, now);
  }

  // ─── Public API ─────────────────────────────────────────────────────────────

  /** The current conversation stage. */
  get currentStage(): ConversationStage { return this._currentStage; }

  /** The previous conversation stage, or null if still in the first stage. */
  get previousStage(): ConversationStage | null { return this._previousStage; }

  /** Ordered list of every stage visited (may include re-visits). */
  get stageHistory(): readonly ConversationStage[] { return this._stageHistory; }

  /** Immutable audit log of every transition. */
  get transitionLog(): readonly TransitionRecord[] { return this._transitionLog; }

  /** True if the machine is in a terminal stage. */
  get isTerminal(): boolean { return isTerminalStage(this._currentStage); }

  /**
   * Returns a frozen snapshot of the current state.
   */
  getState(now: number = Date.now()): ConversationState {
    return new ConversationState({
      currentStage: this._currentStage,
      previousStage: this._previousStage,
      stageHistory: [...this._stageHistory],
      stageEnteredAt: this._stageEnteredAt,
      snapshotAt: now,
      memory: this._memory,
      progress: this._progress,
    });
  }

  /**
   * Dispatches a signal to the state machine.
   *
   * The machine:
   * 1. Updates progress/memory from the signal payload.
   * 2. Determines whether a stage transition is needed.
   * 3. Validates and applies the transition.
   * 4. Returns the new state snapshot.
   *
   * @throws {TransitionError} if a ForceStageSignal targets an invalid stage.
   */
  dispatch(signal: ConversationSignal, now: number = Date.now()): ConversationState {
    // Apply side effects from the signal to memory and progress
    this._applySignalSideEffects(signal, now);

    // Determine if the signal requests a stage transition
    const targetStage = this._resolveTargetStage(signal);
    if (targetStage !== null) {
      this._transition(targetStage, signal, now);
    }

    return this.getState(now);
  }

  /**
   * Attempts to transition to a specific stage.
   * Returns true if the transition succeeded, false if rejected.
   */
  tryTransitionTo(
    stage: ConversationStage,
    signal: ConversationSignal,
    now: number = Date.now()
  ): boolean {
    if (!isTransitionAllowed(this._currentStage, stage)) return false;
    this._transition(stage, signal, now);
    return true;
  }

  // ─── Signal Side Effects ────────────────────────────────────────────────────

  private _applySignalSideEffects(signal: ConversationSignal, _now: number): void {
    switch (signal.type) {
      case 'AGENT_TURN_COMPLETED':
        this._progress.recordAgentTurn(this._currentStage);
        if (signal.containedQuestion) {
          this._progress.recordQuestion(this._currentStage);
        }
        break;

      case 'QUESTION_ASKED':
        this._progress.recordQuestion(this._currentStage);
        break;

      case 'CUSTOMER_INTERRUPTED':
        this._progress.recordInterruption(this._currentStage);
        break;

      case 'OBJECTION_RAISED':
        this._memory.addObjection(signal.topic, signal.verbatim);
        break;

      case 'OBJECTION_RESOLVED':
        this._memory.resolveObjection(signal.topic);
        break;

      case 'PAIN_POINT_IDENTIFIED':
        this._memory.addPainPoint(signal.description);
        break;

      case 'QUALIFICATION_DATA_GATHERED':
        if (signal.field === 'budget') this._memory.setBudget(signal.value as string);
        if (signal.field === 'timeline') this._memory.setTimeline(signal.value as string);
        if (signal.field === 'decisionMaker') this._memory.setIsDecisionMaker(signal.value as boolean);
        break;

      case 'COMMITMENT_MADE':
        this._memory.addCommitment(signal.description);
        break;

      // Signals that are pure transition triggers — no side effects on data
      case 'CUSTOMER_RESPONDED':
      case 'CUSTOMER_SILENT':
      case 'ADVANCE_STAGE':
      case 'FORCE_STAGE':
      case 'CALL_ENDED':
        break;
    }
  }

  // ─── Target Stage Resolution ────────────────────────────────────────────────

  private _resolveTargetStage(signal: ConversationSignal): ConversationStage | null {
    switch (signal.type) {
      case 'CALL_ENDED':
        return ConversationStage.CALL_COMPLETED;

      case 'FORCE_STAGE':
        return signal.targetStage;

      case 'ADVANCE_STAGE':
        return this._nextFunnelStage();

      case 'OBJECTION_RAISED':
        // Only auto-route if not already in objection handling
        if (this._currentStage !== ConversationStage.OBJECTION_HANDLING) {
          return ConversationStage.OBJECTION_HANDLING;
        }
        return null;

      default:
        return null;
    }
  }

  // ─── Transition Application ─────────────────────────────────────────────────

  private _transition(
    to: ConversationStage,
    signal: ConversationSignal,
    now: number
  ): void {
    if (isTerminalStage(this._currentStage)) {
      // Silently ignore — terminal stages never transition
      return;
    }

    // CALL_COMPLETED is always reachable as an emergency exit
    if (to !== ConversationStage.CALL_COMPLETED && !isTransitionAllowed(this._currentStage, to)) {
      throw new TransitionError(
        this._currentStage,
        to,
        `Not in the allowed transition set for stage ${this._currentStage}`
      );
    }

    const record: TransitionRecord = {
      from: this._currentStage,
      to,
      signal,
      occurredAt: now,
    };

    this._progress.exitStage(this._currentStage, now);
    this._previousStage = this._currentStage;
    this._currentStage = to;
    this._stageHistory.push(to);
    this._stageEnteredAt = now;
    this._transitionLog.push(record);
    this._progress.enterStage(to, now);
  }

  // ─── Funnel Advancement ─────────────────────────────────────────────────────

  /**
   * Returns the next stage in the canonical funnel order, or
   * CALL_COMPLETED if we are at the end.
   */
  private _nextFunnelStage(): ConversationStage {
    const currentIndex = FUNNEL_ORDER.indexOf(this._currentStage);
    if (currentIndex === -1 || currentIndex >= FUNNEL_ORDER.length - 1) {
      return ConversationStage.CALL_COMPLETED;
    }
    // Find the next stage in the funnel that is actually allowed
    for (let i = currentIndex + 1; i < FUNNEL_ORDER.length; i++) {
      const candidate = FUNNEL_ORDER[i];
      if (isTransitionAllowed(this._currentStage, candidate)) {
        return candidate;
      }
    }
    return ConversationStage.CALL_COMPLETED;
  }
}

/**
 * @module ConversationStateFactory
 *
 * Creates fully-initialised `ConversationStateMachine` instances.
 *
 * ## Purpose
 * Centralises construction so that every session gets a consistent, valid
 * initial state without callers having to manually wire together the
 * memory, progress tracker, and state machine.
 *
 * ## Usage
 * ```ts
 * const machine = ConversationStateFactory.create({
 *   customerName: 'Sarah',
 *   company: 'Acme Corp',
 * });
 * ```
 *
 * ## No AI imports
 * Pure factory — no OpenAI, Exotel, or prompt logic.
 */

import { ConversationStage } from './ConversationStage.js';
import { ConversationMemory } from './ConversationMemory.js';
import { ConversationProgress } from './ConversationProgress.js';
import { ConversationStateMachine } from './ConversationStateMachine.js';
import { ConversationEvaluator } from './ConversationEvaluator.js';
import type { EvaluatorConfig } from './ConversationEvaluator.js';

// ─── Factory Options ──────────────────────────────────────────────────────────

export interface ConversationStateFactoryOptions {
  /**
   * Stage to begin from.
   * @default ConversationStage.GREETING
   */
  initialStage?: ConversationStage;

  /**
   * Pre-populate memory with caller information known before the call.
   */
  preloadedMemory?: {
    customerName?: string;
    company?: string;
    intent?: string;
    painPoints?: string[];
    isDecisionMaker?: boolean;
    budget?: string;
    timeline?: string;
  };

  /**
   * Wall-clock epoch ms to use as the conversation start time.
   * Defaults to Date.now().
   */
  startedAt?: number;

  /**
   * Optional overrides for the evaluator configuration.
   */
  evaluatorConfig?: Partial<EvaluatorConfig>;
}

// ─── Factory Result ───────────────────────────────────────────────────────────

export interface ConversationStateBundle {
  /** The live state machine — call `dispatch()` on every signal. */
  readonly machine: ConversationStateMachine;
  /** The memory object shared with the machine. */
  readonly memory: ConversationMemory;
  /** The progress tracker shared with the machine. */
  readonly progress: ConversationProgress;
  /** The evaluator configured for this session. */
  readonly evaluator: ConversationEvaluator;
}

// ─── ConversationStateFactory ─────────────────────────────────────────────────

export class ConversationStateFactory {
  /**
   * Creates and returns a fully-wired conversation state bundle.
   */
  static create(options: ConversationStateFactoryOptions = {}): ConversationStateBundle {
    const now = options.startedAt ?? Date.now();
    const initialStage = options.initialStage ?? ConversationStage.GREETING;

    // Build memory — optionally pre-seeded with caller data
    const memory = new ConversationMemory();
    if (options.preloadedMemory) {
      const pm = options.preloadedMemory;
      if (pm.customerName) memory.setCustomerName(pm.customerName);
      if (pm.company) memory.setCompany(pm.company);
      if (pm.intent) memory.setIntent(pm.intent);
      if (pm.painPoints) pm.painPoints.forEach((p) => memory.addPainPoint(p));
      if (pm.isDecisionMaker !== undefined) memory.setIsDecisionMaker(pm.isDecisionMaker);
      if (pm.budget) memory.setBudget(pm.budget);
      if (pm.timeline) memory.setTimeline(pm.timeline);
    }

    // Build progress tracker
    const progress = new ConversationProgress(now);

    // Build state machine
    const machine = new ConversationStateMachine(initialStage, memory, progress, now);

    // Build evaluator
    const evaluator = new ConversationEvaluator(options.evaluatorConfig);

    return Object.freeze({ machine, memory, progress, evaluator });
  }
}

/**
 * @module conversation-state
 *
 * Public API for the NIJVOX Conversation State Engine.
 *
 * ## Quick Start
 *
 * ```ts
 * import {
 *   ConversationStateFactory,
 *   ConversationStage,
 *   Signals,
 * } from './conversation-state/index.js';
 *
 * // 1. Create a bundle for a new call
 * const { machine, evaluator } = ConversationStateFactory.create({
 *   preloadedMemory: { customerName: 'Sarah', company: 'Acme Corp' },
 * });
 *
 * // 2. Dispatch signals as events arrive
 * let state = machine.dispatch(Signals.agentTurnCompleted(true));
 *
 * // 3. Ask the evaluator what to do next
 * const recommendation = evaluator.evaluate(state);
 * // → { action: 'ASK_QUESTION', confidence: 1, shouldAdvanceStage: false, ... }
 *
 * // 4. Customer raises an objection → auto-routes to OBJECTION_HANDLING
 * state = machine.dispatch(Signals.objectionRaised('price', "It seems expensive."));
 * // state.currentStage === ConversationStage.OBJECTION_HANDLING
 *
 * // 5. Advance when ready
 * state = machine.dispatch(Signals.advanceStage());
 * ```
 */

// ─── Stages ───────────────────────────────────────────────────────────────────
export {
  ConversationStage,
  STAGE_METADATA,
  ALLOWED_TRANSITIONS,
  FUNNEL_ORDER,
  isTransitionAllowed,
  getReachableStages,
  isTerminalStage,
} from './ConversationStage.js';
export type { StageMetadata } from './ConversationStage.js';

// ─── Memory ───────────────────────────────────────────────────────────────────
export { ConversationMemory } from './ConversationMemory.js';
export type { CustomerObjection, CallCommitment } from './ConversationMemory.js';

// ─── Progress ─────────────────────────────────────────────────────────────────
export { ConversationProgress } from './ConversationProgress.js';
export type { StageStats } from './ConversationProgress.js';

// ─── Signals ──────────────────────────────────────────────────────────────────
export { Signals } from './ConversationSignals.js';
export type {
  ConversationSignal,
  SignalType,
  AgentTurnCompletedSignal,
  QuestionAskedSignal,
  CustomerRespondedSignal,
  CustomerInterruptedSignal,
  CustomerSilentSignal,
  ObjectionRaisedSignal,
  ObjectionResolvedSignal,
  PainPointIdentifiedSignal,
  QualificationDataGatheredSignal,
  CommitmentMadeSignal,
  AdvanceStageSignal,
  ForceStageSignal,
  CallEndedSignal,
} from './ConversationSignals.js';

// ─── State ────────────────────────────────────────────────────────────────────
export { ConversationState } from './ConversationState.js';

// ─── State Machine ────────────────────────────────────────────────────────────
export { ConversationStateMachine, TransitionError } from './ConversationStateMachine.js';
export type { TransitionRecord } from './ConversationStateMachine.js';

// ─── Evaluator ────────────────────────────────────────────────────────────────
export { ConversationEvaluator, DEFAULT_EVALUATOR_CONFIG } from './ConversationEvaluator.js';
export type {
  AgentAction,
  AgentActionType,
  EvaluatorConfig,
} from './ConversationEvaluator.js';

// ─── Factory ──────────────────────────────────────────────────────────────────
export { ConversationStateFactory } from './ConversationStateFactory.js';
export type {
  ConversationStateFactoryOptions,
  ConversationStateBundle,
} from './ConversationStateFactory.js';

