import { ConversationStateFactory, ConversationStage, Signals } from './index.js';

const { machine, evaluator } = ConversationStateFactory.create({
  preloadedMemory: { customerName: 'Sarah', company: 'Acme Corp' },
});

function log(label: string) {
  const state = machine.getState();
  const rec = evaluator.evaluate(state);
  const mem = state.memory.toSnapshot() as any;
  console.log(`\n${'─'.repeat(60)}`);
  console.log(`[${label}]`);
  console.log(`  Stage:        ${state.currentStage}`);
  console.log(`  Previous:     ${state.previousStage ?? 'none'}`);
  console.log(`  History:      ${state.stageHistory.join(' → ')}`);
  console.log(`  Turns/stage:  ${state.turnsInCurrentStage}`);
  console.log(`  Questions:    ${state.questionsInCurrentStage}`);
  console.log(`  Min turns met:${state.hasMetMinimumTurns}`);
  console.log(`  Objections:   ${state.hasUnresolvedObjections}`);
  console.log(`  Pain points:  ${JSON.stringify(mem.painPoints)}`);
  console.log(`  Evaluator → action: ${rec.action} (confidence: ${rec.confidence})`);
  console.log(`             rationale: ${rec.rationale}`);
  console.log(`             advanceStage: ${rec.shouldAdvanceStage}`);
}

// ── T1: Call opens ─────────────────────────────────────────────────────────
log('T1: Call opens — GREETING');

// ── T2: Agent completes greeting turn with a question ──────────────────────
machine.dispatch(Signals.agentTurnCompleted(true));
log('T2: Agent completes greeting turn (with question)');

// ── T3: Advance to RAPPORT ─────────────────────────────────────────────────
machine.dispatch(Signals.advanceStage());
log('T3: Advance → RAPPORT');

// ── T4: Advance to DISCOVERY ───────────────────────────────────────────────
machine.dispatch(Signals.agentTurnCompleted(true));
machine.dispatch(Signals.advanceStage());
log('T4: Advance → DISCOVERY');

// ── T5: Pain point identified ──────────────────────────────────────────────
machine.dispatch(Signals.painPointIdentified('Manual outreach is too slow'));
machine.dispatch(Signals.agentTurnCompleted(true));
log('T5: Pain point identified + agent turn');

// ── T6: Customer raises an objection → auto-routes ────────────────────────
machine.dispatch(Signals.objectionRaised('price', "It seems expensive for our budget."));
log('T6: Objection raised → auto-routes to OBJECTION_HANDLING');

// ── T7: Objection resolved → back to QUALIFICATION ────────────────────────
machine.dispatch(Signals.objectionResolved('price'));
machine.dispatch(Signals.advanceStage());
log('T7: Objection resolved → advance → QUALIFICATION');

// ── T8: Qualification data gathered ───────────────────────────────────────
machine.dispatch(Signals.qualificationData('decisionMaker', true));
machine.dispatch(Signals.qualificationData('budget', '$5,000/mo'));
machine.dispatch(Signals.qualificationData('timeline', 'Q3 2026'));
machine.dispatch(Signals.agentTurnCompleted(false));
log('T8: Full qualification data gathered');

// ── T9: Advance to PRESENTATION ───────────────────────────────────────────
machine.dispatch(Signals.advanceStage());
log('T9: Advance → PRESENTATION');

// ── T10: Agent presents, customer responds positively ─────────────────────
machine.dispatch(Signals.agentTurnCompleted(true));
machine.dispatch(Signals.customerResponded('positive', true));
log('T10: Presentation delivered, positive response');

// ── T11: Commitment + close ────────────────────────────────────────────────
machine.dispatch(Signals.advanceStage());
machine.dispatch(Signals.commitmentMade('Demo booked for Thursday 2 PM'));
log('T11: Advance → CLOSING, commitment made');

// ── T12: Call ends ─────────────────────────────────────────────────────────
machine.dispatch(Signals.callEnded('agent_closed'));
log('T12: Call ended → CALL_COMPLETED');

console.log('\n' + '═'.repeat(60));
console.log('Transition log:');
machine.transitionLog.forEach((t, i) => {
  console.log(`  ${i + 1}. ${t.from.padEnd(20)} → ${t.to} (signal: ${t.signal.type})`);
});

