/**
 * Integration demo — shows what the OpenAI session receives as:
 * 1. The initial system instruction (at session creation)
 * 2. The updated instruction after a customer objection
 */
import { ConversationSessionContext } from './ConversationSessionContext.js';
import { Signals } from '../../conversation-state/index.js';

const policyContext = {
  agentName: 'Alex',
  companyName: 'NIJVOX',
  productDescription: 'an AI-powered outbound sales calling platform',
  campaignGoal: 'schedule a 20-minute product demo with the decision-maker',
  existingScript: "Hi, I'm calling about how we help sales teams automate outreach. Are you handling outbound calls manually right now?",
  caller: { firstName: 'Sarah', company: 'Acme Corp' },
};

const ctx = new ConversationSessionContext({
  policyContext,
  preloadedMemory: { customerName: 'Sarah', company: 'Acme Corp' },
});

// ── EXAMPLE 1: Initial instruction ────────────────────────────────────────────
const initial = ctx.buildInitialInstruction();
const DIVIDER = '\n' + '█'.repeat(70) + '\n';

console.log(DIVIDER);
console.log('EXAMPLE 1: INITIAL INSTRUCTION (passed to OpenAI at session creation)');
console.log(DIVIDER);

// Show only the last 2 sections + dynamic state to keep output manageable
const sections = initial.split(/\n─{60}\n## /);
const lastTwo = sections.slice(-2).join('\n─────────────────────────────────────────────────────────────\n## ');
console.log('... [policy sections truncated for brevity] ...\n');
console.log('─'.repeat(60) + '\n## ' + lastTwo);

// ── Simulate: agent greeted, customer responded ────────────────────────────────
ctx.dispatchSignal(Signals.agentTurnCompleted(true));   // greeting turn with question
ctx.dispatchSignal(Signals.advanceStage());             // move to RAPPORT
ctx.dispatchSignal(Signals.agentTurnCompleted(true));   // rapport turn
ctx.dispatchSignal(Signals.advanceStage());             // move to DISCOVERY
ctx.dispatchSignal(Signals.painPointIdentified('Sales team spends 6+ hours a day on manual dialling'));
ctx.dispatchSignal(Signals.agentTurnCompleted(true));   // discovery Q1

// ── EXAMPLE 2: Updated instruction after a customer objection ─────────────────
console.log(DIVIDER);
console.log('EXAMPLE 2: UPDATED INSTRUCTION AFTER CUSTOMER OBJECTION');
console.log(DIVIDER);

const result = ctx.dispatchSignal(
  Signals.objectionRaised('price', "That sounds expensive — we're a small team.")
);

console.log('stateChanged:         ', result.stateChanged);
console.log('currentStageLabel:    ', result.currentStageLabel);
console.log('\nUpdated dynamic state section (sent via session.update):');
console.log('─'.repeat(60));

if (result.updatedInstruction) {
  // Extract just the LIVE CONVERSATION STATE block
  const stateIdx = result.updatedInstruction.indexOf('## LIVE CONVERSATION STATE');
  const stateBlock = stateIdx !== -1
    ? result.updatedInstruction.slice(stateIdx)
    : result.updatedInstruction.slice(-1500);
  console.log(stateBlock);
}

