    35→import type { IOpenAIRealtimeSession } from '../providers/openai/OpenAIRealtimeSession.js';
    36→import type { Timestamp } from '../types/index.js';
    37→import { VoiceEngineError, ErrorCode } from '../errors/index.js';
    38→
    39→// ─── Bridge Event Types ───────────────────────────────────────────────────────
    40→
    41→/** Payload emitted when the provider sends an outbound audio delta. */
    42→export interface BridgeAudioReadyEvent {
    43→  readonly type: 'bridge.audio_ready';
    44→  /** Base64-encoded audio delta from the provider. */
    45→  readonly base64Delta: string;
    46→  /** Provider response identifier. */
    47→  readonly responseId: string;
    48→  /** Provider item identifier. */
    49→  readonly itemId: string;
    50→  /** Wall-clock timestamp. */
    51→  readonly timestamp: Timestamp;
    52→}
    53→
    54→/** Payload emitted when the provider WebSocket disconnects. */
    55→export interface BridgeDisconnectedEvent {
    56→  readonly type: 'bridge.disconnected';
    57→  /** WebSocket close code. */
    58→  readonly code: number;
    59→  /** Human-readable disconnect reason. */
    60→  readonly reason: string;
    61→  /** Whether the disconnect was clean (code === 1000). */
    62→  readonly wasClean: boolean;
    63→  readonly timestamp: Timestamp;
    64→}
    65→
    66→/** Payload emitted when the provider reports an error. */
    67→export interface BridgeErrorEvent {
    68→  readonly type: 'bridge.error';
    69→  readonly message: string;
    70→  readonly errorType: string;
    71→  /** Whether this error is fatal to the session. */
    72→  readonly fatal: boolean;
    73→  readonly timestamp: Timestamp;
    74→}
    75→
    76→/** Payload emitted when the provider VAD detects speech start (barge-in signal). */
    77→export interface BridgeSpeechDetectedEvent {
    78→  readonly type: 'bridge.speech_detected';
    79→  readonly audioStartMs: number;
    80→  readonly timestamp: Timestamp;
    81→}
    82→
    83→/** Union of all events emitted by `RealtimeBridge`. */
    84→export type BridgeEvent =
    85→  | BridgeAudioReadyEvent
    86→  | BridgeDisconnectedEvent
    87→  | BridgeErrorEvent
    88→  | BridgeSpeechDetectedEvent;
    89→
    90→/** String union of all bridge event types. */
    91→export type BridgeEventType = BridgeEvent['type'];
    92→
    93→/** Handler signature for a typed bridge event. */
    94→export type BridgeEventHandler<T extends BridgeEvent = BridgeEvent> = (event: T) => void;
    95→
    96→// ─── Public Interface ─────────────────────────────────────────────────────────
    97→
    98→/**
    99→ * Public contract for the realtime bridge between `MediaSession`
   100→ * and an AI provider realtime session.
   101→ */
   102→export interface IRealtimeBridge {
   103→  /** Whether the provider session is currently connected. */
   104→  readonly isConnected: boolean;
   105→
   106→  /**
   107→   * Opens the provider WebSocket session and wires all event handlers.
   108→   * Must be called before `forwardAudio()` or `interrupt()`.
   109→   *
   110→   * @throws {VoiceEngineError} if the provider session fails to connect.
   111→   */
   112→  connect(): Promise<void>;
   113→
   114→  /**
   115→   * Forwards a base64-encoded audio payload to the AI provider.
   116→   * Fire-and-forget; silently ignored if not connected.
   117→   *
   118→   * @param base64 - Base64-encoded audio chunk from the caller.
   119→   */
   120→  forwardAudio(base64: string): void;
   121→
   122→  /**
   123→   * Cancels the provider's current in-progress response (barge-in).
   124→   * Silently ignored if not connected.
   125→   */
   126→  interrupt(): Promise<void>;
   127→
   128→  /**
   129→   * Gracefully closes the provider session and removes all event handlers.
   130→   * Safe to call multiple times; subsequent calls are no-ops.
   131→   */
   132→  disconnect(): Promise<void>;
   133→
   134→  /** Subscribes to a typed bridge event. */
   135→  on<T extends BridgeEventType>(
   136→    type: T,
   137→    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
   138→  ): void;
   139→
   140→  /** Unsubscribes from a typed bridge event. */
   141→  off<T extends BridgeEventType>(
   142→    type: T,
   143→    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
   144→  ): void;
   145→}
   146→
   147→// ─── Dependencies ─────────────────────────────────────────────────────────────
   148→
   149→/** Injected dependencies for `RealtimeBridge`. */
   150→export interface RealtimeBridgeDependencies {
   151→  /** The AI provider realtime session to bridge. */
   152→  readonly providerSession: IOpenAIRealtimeSession;
   153→  /** The media session that owns this call. */
   154→  readonly mediaSession: IMediaSession;
   155→  /** Structured logger. */
   156→  readonly logger: ILogger;
   157→  /** Session identifier for log correlation. */
   158→  readonly sessionId: string;
   159→}
   160→
   161→// ─── Implementation ───────────────────────────────────────────────────────────
   162→
   163→/**
   164→ * Production implementation of `IRealtimeBridge`.
   165→ */
   166→export class RealtimeBridge implements IRealtimeBridge {
   167→  private readonly _provider: IOpenAIRealtimeSession;
   168→  private readonly _mediaSession: IMediaSession;
   169→  private readonly _logger: ILogger;
   170→  private readonly _sessionId: string;
   171→
   172→  private _connected = false;
   173→  private _destroyed = false;
   174→
   175→  private readonly _handlers = new Map<BridgeEventType, Set<BridgeEventHandler>>();
   176→
   177→  constructor(deps: Readonly<RealtimeBridgeDependencies>) {
   178→    this._provider = deps.providerSession;
   179→    this._mediaSession = deps.mediaSession;
   180→    this._logger = deps.logger.child({ component: 'RealtimeBridge', sessionId: deps.sessionId });
   181→    this._sessionId = deps.sessionId;
   182→  }
   183→
   184→  // ─── Accessors ───────────────────────────────────────────────────────────────
   185→
   186→  get isConnected(): boolean {
   187→    return this._connected && this._provider.isConnected;
   188→  }
   189→
   190→  // ─── Lifecycle ────────────────────────────────────────────────────────────────
   191→
   192→  /**
   193→   * Opens the provider WebSocket and registers all event handlers.
   194→   */
   195→  async connect(): Promise<void> {
   196→    this._assertNotDestroyed('connect');
   197→
   198→    this._logger.info('RealtimeBridge connecting to provider');
   199→
   200→    this._wireProviderHandlers();
   201→
   202→    try {
   203→      await this._provider.connect();
   204→    } catch (err) {
   205→      this._logger.error('RealtimeBridge provider connect failed', { error: String(err) });
   206→      throw new VoiceEngineError(
   207→        `RealtimeBridge failed to connect provider: ${String(err)}`,
   208→        ErrorCode.PROVIDER_UNAVAILABLE,
   209→        true,
   210→        { sessionId: this._sessionId }
   211→      );
   212→    }
   213→
   214→    this._connected = true;
   215→    this._logger.info('RealtimeBridge connected');
   216→  }
   217→
   218→  /**
   219→   * Forwards caller audio to the AI provider.
   220→   * Fire-and-forget; silently ignored when not connected.
   221→   */
   222→  forwardAudio(base64: string): void {
   223→    if (!this.isConnected || this._destroyed) return;
   224→    this._provider.sendAudio(base64);
   225→  }
   226→
   227→  /**
   228→   * Cancels the current provider response (barge-in).
   229→   */
   230→  async interrupt(): Promise<void> {
   231→    if (!this.isConnected || this._destroyed) return;
   232→
   233→    this._logger.debug('RealtimeBridge signalling interrupt to provider');
   234→    await this._provider.interrupt();
   235→  }
   236→
   237→  /**
   238→   * Closes the provider session and removes all handlers.
   239→   */
   240→  async disconnect(): Promise<void> {
   241→    if (this._destroyed) return;
   242→    this._destroyed = true;
   243→    this._connected = false;
   244→
   245→    this._logger.info('RealtimeBridge disconnecting');
   246→    await this._provider.close();
   247→    this._handlers.clear();
   248→  }
   249→
   250→  // ─── Event Bus ───────────────────────────────────────────────────────────────
   251→
   252→  on<T extends BridgeEventType>(
   253→    type: T,
   254→    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
   255→  ): void {
   256→    if (!this._handlers.has(type)) this._handlers.set(type, new Set());
   257→    this._handlers.get(type)!.add(handler as BridgeEventHandler);
   258→  }
   259→
   260→  off<T extends BridgeEventType>(
   261→    type: T,
   262→    handler: BridgeEventHandler<Extract<BridgeEvent, { type: T }>>
   263→  ): void {
   264→    this._handlers.get(type)?.delete(handler as BridgeEventHandler);
   265→  }
   266→
   267→  // ─── Private: Provider Event Wiring ─────────────────────────────────────────
   268→
   269→  /**
   270→   * Registers all necessary event handlers on the provider session.
   271→   * Called once during `connect()`.
   272→   */
   273→  private _wireProviderHandlers(): void {
   274→    // Outbound audio from AI → caller
   275→    this._provider.on('realtime.audio_received', (event) => {
   276→      if (this._destroyed) return;
   277→      this._emit({
   278→        type: 'bridge.audio_ready',
   279→        base64Delta: event.delta,
   280→        responseId: event.responseId,
   281→        itemId: event.itemId,
   282→        timestamp: event.timestamp,
   283→      } satisfies BridgeAudioReadyEvent);
   284→    });
   285→
   286→    // Server VAD detected caller speech → barge-in signal
   287→    this._provider.on('realtime.speech_started', (event) => {
   288→      if (this._destroyed) return;
   289→      const now = Date.now() as Timestamp;
   290→
   291→      this._logger.debug('RealtimeBridge: provider VAD speech_started, signalling interruption', {
   292→        audioStartMs: event.audioStartMs,
   293→      });
   294→
   295→      this._emit({
   296→        type: 'bridge.speech_detected',
   297→        audioStartMs: event.audioStartMs,
   298→        timestamp: now,
   299→      } satisfies BridgeSpeechDetectedEvent);
   300→
   301→      // Signal barge-in to the media session
   302→      this._mediaSession.signalInterruption(now).catch((err: unknown) => {
   303→        this._logger.warn('RealtimeBridge: mediaSession.signalInterruption failed', {
   304→          error: String(err),
   305→        });
   306→      });
   307→    });
   308→
   309→    // Provider WebSocket disconnected
   310→    this._provider.on('realtime.disconnected', (event) => {
   311→      if (this._destroyed) return;
   312→      this._connected = false;
   313→
   314→      this._logger.info('RealtimeBridge: provider disconnected', {
   315→        code: event.code,
   316→        reason: event.reason,
   317→      });
   318→
   319→      this._emit({
   320→        type: 'bridge.disconnected',
   321→        code: event.code,
   322→        reason: event.reason,
   323→        wasClean: event.wasClean,
   324→        timestamp: event.timestamp,
   325→      } satisfies BridgeDisconnectedEvent);
   326→    });
   327→
   328→    // Provider error
   329→    this._provider.on('realtime.error', (event) => {
   330→      if (this._destroyed) return;
   331→
   332→      this._logger.error('RealtimeBridge: provider error', {
   333→        errorType: event.errorType,
   334→        message: event.message,
   335→        fatal: event.fatal,
   336→      });
   337→
   338→      this._emit({
   339→        type: 'bridge.error',
   340→        message: event.message,
   341→        errorType: event.errorType,
   342→        fatal: event.fatal,
   343→        timestamp: event.timestamp,
   344→      } satisfies BridgeErrorEvent);
   345→    });
   346→  }
   347→
   348→  // ─── Private Helpers ─────────────────────────────────────────────────────────
   349→
   350→  private _assertNotDestroyed(method: string): void {
   351→    if (this._destroyed) {
   352→      throw new VoiceEngineError(
   353→        `RealtimeBridge.${method}() called after disconnect()`,
   354→        ErrorCode.PIPELINE_ABORTED,
   355→        false,
   356→        { sessionId: this._sessionId }
   357→      );
   358→    }
   359→  }
   360→
   361→  private _emit(event: BridgeEvent): void {
   362→    const handlers = this._handlers.get(event.type);
   363→    if (!handlers) return;
   364→    Array.from(handlers).forEach((handler) => {
   365→      try {
   366→        handler(event);
   367→      } catch (err) {
   368→        this._logger.warn('RealtimeBridge: event handler threw', {
   369→          type: event.type,
   370→          error: String(err),
   371→        });
   372→      }
   373→    });
   374→  }
   375→}
   376→

